mapper.select:
SELECT 
FROM blog_article_version
WHERE article_id = #{articleId}
  AND version_no = #{versionNo}
LIMIT 1

SELECT MAX(version_no)
FROM blog_article_version
WHERE article_id = #{articleId}

mapper.delete:
DELETE FROM blog_article_version
WHERE article_id = #{articleId}
  AND id NOT IN (
    SELECT id FROM (
        SELECT id FROM blog_article_version
        WHERE article_id = #{articleId}
        ORDER BY version_no DESC
        LIMIT #{keepCount}
    ) AS t
  )

mapper.select:
SELECT COUNT(*)
FROM blog_article_version
WHERE article_id = #{articleId}
